"use client";

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { CartService } from "@/services/cart.service";
import Image from "next/image";
import { Trash2, Plus, Minus, Loader2, ArrowRight } from "lucide-react";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import toast from "react-hot-toast";

export default function CartPage() {
  const queryClient = useQueryClient();

  const { data: cartData, isLoading } = useQuery({
    queryKey: ["cart"],
    queryFn: CartService.getCart,
  });

  const updateMutation = useMutation({
    mutationFn: ({ productId, count }: { productId: string; count: number }) => 
      CartService.updateCartQuantity(productId, count),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["cart"] });
    },
  });

  const removeMutation = useMutation({
    mutationFn: CartService.removeFromCart,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["cart"] });
      toast.success("Item removed from cart");
    },
  });

  const clearMutation = useMutation({
    mutationFn: CartService.clearCart,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["cart"] });
      toast.success("Cart cleared");
    },
  });

  if (isLoading) {
    return (
      <div className="flex-1 flex justify-center items-center h-[50vh]">
        <Loader2 className="w-12 h-12 animate-spin text-orange-600" />
      </div>
    );
  }

  const cart = cartData?.data;

  if (!cart || cart.products.length === 0) {
    return (
      <div className="flex-1 flex flex-col justify-center items-center p-12 text-center min-h-[60vh]">
        <div className="w-48 h-48 relative mb-8 opacity-50">
          <Image src="https://cdni.iconscout.com/illustration/premium/thumb/empty-cart-7359557-6024626.png" alt="Empty Cart" fill className="object-contain" />
        </div>
        <h2 className="text-3xl font-bold mb-3 text-slate-800 dark:text-slate-100">Your Cart is Empty!</h2>
        <p className="text-slate-500 mb-8 max-w-sm">Looks like you haven&apos;t added anything to your cart yet.</p>
        <Link href="/products" className="px-8 py-4 bg-orange-600 text-white font-bold rounded-full hover:bg-orange-700 transition shadow-lg shadow-orange-500/30">
          Start Shopping
        </Link>
      </div>
    );
  }

  return (
    <div className="bg-slate-50 dark:bg-slate-950 flex-1 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-8">Shopping Cart</h1>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Cart Items */}
          <div className="lg:col-span-2 space-y-4">
            <div className="flex justify-between items-center mb-4 px-2">
              <span className="text-slate-600 dark:text-slate-400 font-medium">
                {cart.products.length} Items in your cart
              </span>
              <button 
                onClick={() => clearMutation.mutate()}
                className="text-red-500 text-sm font-semibold hover:text-red-600 transition"
              >
                Clear Cart
              </button>
            </div>

            <AnimatePresence>
              {cart.products.map((item) => (
                <motion.div 
                  key={item._id}
                  layout
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, x: -50 }}
                  className="flex flex-col sm:flex-row items-center gap-6 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800"
                >
                  <Link href={`/products/${item.product.id}`} className="relative w-32 h-32 flex-shrink-0 bg-slate-100 dark:bg-slate-800 rounded-xl overflow-hidden self-start sm:self-center">
                    <Image src={item.product.imageCover} alt={item.product.title} fill className="object-cover" />
                  </Link>
                  
                  <div className="flex-1 flex flex-col min-w-0 w-full">
                    <div className="flex justify-between items-start gap-4 mb-2">
                      <Link href={`/products/${item.product.id}`}>
                        <h3 className="font-semibold text-lg text-slate-900 dark:text-white hover:text-orange-600 transition line-clamp-2">
                          {item.product.title}
                        </h3>
                      </Link>
                      <button 
                        onClick={() => removeMutation.mutate(item.product.id)}
                        disabled={removeMutation.isPending}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-lg transition"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                    
                    <span className="text-sm text-slate-500 mb-4">{item.product.category.name}</span>
                    
                    <div className="flex items-center justify-between mt-auto">
                      <div className="flex items-center gap-3 bg-slate-100 dark:bg-slate-800 rounded-lg p-1">
                        <button 
                          onClick={() => updateMutation.mutate({ productId: item.product.id, count: item.count - 1 })}
                          disabled={item.count <= 1 || updateMutation.isPending}
                          className="w-8 h-8 flex items-center justify-center bg-white dark:bg-slate-700 rounded-md shadow-sm disabled:opacity-50 text-slate-700 dark:text-slate-200"
                        >
                          <Minus className="w-4 h-4" />
                        </button>
                        <span className="w-8 text-center font-medium text-slate-900 dark:text-white">
                          {item.count}
                        </span>
                        <button 
                          onClick={() => updateMutation.mutate({ productId: item.product.id, count: item.count + 1 })}
                          disabled={updateMutation.isPending}
                          className="w-8 h-8 flex items-center justify-center bg-white dark:bg-slate-700 rounded-md shadow-sm text-slate-700 dark:text-slate-200"
                        >
                          <Plus className="w-4 h-4" />
                        </button>
                      </div>
                      
                      <div className="text-right">
                        <span className="font-bold text-lg text-slate-900 dark:text-white">EGP {item.price * item.count}</span>
                        {item.count > 1 && (
                          <div className="text-xs text-slate-500">EGP {item.price} each</div>
                        )}
                      </div>
                    </div>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>
          </div>

          {/* Order Summary */}
          <div className="lg:col-span-1">
            <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 sticky top-24">
              <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-6">Order Summary</h3>
              
              <div className="space-y-4 mb-6">
                <div className="flex justify-between text-slate-600 dark:text-slate-400">
                  <span>Subtotal</span>
                  <span className="font-medium text-slate-900 dark:text-white">EGP {cart.totalCartPrice}</span>
                </div>
                <div className="flex justify-between text-slate-600 dark:text-slate-400">
                  <span>Shipping limit</span>
                  <span className="font-medium text-green-600">Free</span>
                </div>
              </div>
              
              <div className="border-t border-slate-200 dark:border-slate-800 pt-6 mb-8">
                <div className="flex justify-between items-center text-lg">
                  <span className="font-bold text-slate-900 dark:text-white">Total</span>
                  <span className="font-black text-2xl text-orange-600">EGP {cart.totalCartPrice}</span>
                </div>
              </div>
              
              <Link 
                href="/checkout"
                className="w-full flex items-center justify-center gap-2 bg-orange-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-orange-700 transition shadow-lg shadow-orange-500/30"
              >
                Proceed to Checkout <ArrowRight className="w-5 h-5" />
              </Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
